it = iter(sys.stdin.read().split())
N = int(next(it))
stations = [int(next(it)) for _ in range(N)]
K = int(next(it))

def possible(dist):
    count = 0
    prev = 0
    for station in stations:
        if station - prev > dist:
            if count + 1 > K:
                return False
            count += 1
            prev = station - dist
        else:
            prev = station
    return True

low, high = 0, 10**8
while low < high:
    mid = (low + high) // 2
    if possible(mid):
        high = mid
    else:
        low = mid + 1
