#include <bits/stdc++.h>
using namespace std;
int main(){
    int N;
    if(!(cin >> N)) return 0;
    vector<int> stations(N);
    for(int i = 0; i < N; i++) cin >> stations[i];
    int K; cin >> K;
    auto possible = [&](int dist) {
        int count = 0;
        int prev = 0;
        for (int station : stations) {
            if (station - prev > dist) {
                if (count + 1 > K) {
                    return false;
                }
                count += 1;
                prev = station - dist;
            } else {
                prev = station;
            }
        }
        return true;
    };
    int low = 0, high = 1e8;
    while (low < high) {
        int mid = low + (high - low) / 2;
        if (possible(mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    cout << low << endl;
    return 0;
}
